const fs=require("fs"),path=require("path"),mongoose=require("mongoose");require("dotenv").config();const BASE_URL="https://www.universcolis.fr";mongoose.connect(process.env.MONGO_URL);const Article=require("../../models/Article");async function getStaticPages(){return[{loc:"/",priority:1},{loc:"/suivi",priority:1},{loc:"/conseils",priority:1},{loc:"/mon-materiel",priority:.6},{loc:"/comment-ca-marche",priority:.4},{loc:"/qui-sommes-nous",priority:.4},{loc:"/politique-confidentialite",priority:.4},{loc:"/mentions-legales",priority:.4}]}async function getArticles(){return(await Article.find({}).select("slug publishedDate modifiedDate cardImg").lean()).map(e=>{let i;if(e.modifiedDate){const t=new Date(e.modifiedDate);isNaN(t)||(i=t.toISOString().split("T")[0])}else if(e.publishedDate){const t=new Date(e.publishedDate);isNaN(t)||(i=t.toISOString().split("T")[0])}return{loc:`/conseils/${e.slug}`,priority:.9,lastmod:i,image:e.cardImg?`${BASE_URL}/static/img/cardImg/${e.cardImg}`:null}})}async function getImages(e,i){const t=[{page:"/",images:[`${BASE_URL}/static/img/logo.png`]},{page:"/mon-materiel",images:[`${BASE_URL}/static/img/materiel.jpg`]}];return i.forEach(e=>{e.image&&t.push({page:e.loc,images:[e.image]})}),t}function generateSitemapIndex(){return`<?xml version="1.0" encoding="UTF-8"?>\n<sitemapindex xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n  <sitemap>\n    <loc>${BASE_URL}/sitemap-pages.xml</loc>\n  </sitemap>\n  <sitemap>\n    <loc>${BASE_URL}/sitemap-articles.xml</loc>\n  </sitemap>\n  <sitemap>\n    <loc>${BASE_URL}/sitemap-images.xml</loc>\n  </sitemap>\n</sitemapindex>`}function generatePagesSitemap(e){return`<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${e.map(e=>`\n  <url>\n    <loc>${BASE_URL}${e.loc}</loc>\n    <priority>${e.priority}</priority>\n  </url>`).join("")}\n</urlset>`}function generateArticlesSitemap(e){return`<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${e.map(e=>`\n  <url>\n    <loc>${BASE_URL}${e.loc}</loc>\n    <priority>${e.priority}</priority>\n    ${e.lastmod?`<lastmod>${e.lastmod}</lastmod>`:""}\n    ${e.image?`<image:image xmlns:image="http://www.google.com/schemas/sitemap-image/1.1"><image:loc>${e.image}</image:loc></image:image>`:""}\n  </url>`).join("")}\n</urlset>`}function generateImagesSitemap(e){return`<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9"\n        xmlns:image="http://www.google.com/schemas/sitemap-image/1.1">\n${e.map(e=>`<url>\n    <loc>${BASE_URL}${e.page}</loc>\n    ${e.images.map(e=>`<image:image><image:loc>${e}</image:loc></image:image>`).join("")}\n  </url>`).join("")}\n</urlset>`}function generateAtomFeed(e){return`<?xml version="1.0" encoding="utf-8"?>\n<feed xmlns="http://www.w3.org/2005/Atom">\n  <title>UniversColis - Nouveaux conseils et guides</title>\n  <link href="${BASE_URL}/atom.xml" rel="self"/>\n  <link href="https://pubsubhubbub.appspot.com/" rel="hub"/>\n  <updated>${(new Date).toISOString()}</updated>\n  <id>${BASE_URL}/</id>\n  ${e.map(e=>`\n    <entry>\n      <title>${e.loc.replace("/conseils/","").replace(/-/g," ")}</title>\n      <link href="${BASE_URL}${e.loc}"/>\n      <id>${BASE_URL}${e.loc}</id>\n      ${e.lastmod?`<updated>${e.lastmod}</updated>`:""}\n      <summary>Un nouveau guide est disponible.</summary>\n    </entry>\n  `).join("")}\n</feed>`}async function main(){const e=path.join(__dirname,"..");fs.existsSync(e)||fs.mkdirSync(e);const i=await getStaticPages(),t=await getArticles(),n=await getImages(i,t);fs.writeFileSync(path.join(e,"sitemap.xml"),generateSitemapIndex()),fs.writeFileSync(path.join(e,"sitemap-pages.xml"),generatePagesSitemap(i)),fs.writeFileSync(path.join(e,"sitemap-articles.xml"),generateArticlesSitemap(t)),fs.writeFileSync(path.join(e,"sitemap-images.xml"),generateImagesSitemap(n)),fs.writeFileSync(path.join(e,"atom.xml"),generateAtomFeed(t)),console.log("Sitemaps et Atom feed générés dans /static"),mongoose.disconnect()}main().catch(e=>{console.error(e),mongoose.disconnect(),process.exit(1)});